# Environment variables — set these in the Lambda configuration, not in code.
RESULTS_BUCKET = os.environ.get("RESULTS_BUCKET")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")

# Allowed image content types
ALLOWED_CONTENT_TYPES = frozenset({
    "image/jpeg",
    "image/png",
    "image/webp",
    "image/gif",
})

# Maximum image size we're willing to process (10 MB)
MAX_IMAGE_SIZE_BYTES = 10 * 1024 * 1024

# Initialize clients outside the handler for connection reuse across
# warm invocations.
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")


def _validate_environment():
    """Fail fast if required environment variables are missing."""
    missing = []
    if not RESULTS_BUCKET:
        missing.append("RESULTS_BUCKET")
    if not SNS_TOPIC_ARN:
        missing.append("SNS_TOPIC_ARN")
    if missing:
        raise EnvironmentError(
            f"Missing required environment variables: {', '.join(missing)}"
        )


def _validate_s3_key(key: str) -> str:
    """
    Sanitise and validate the S3 object key to prevent path-traversal or
    unexpected object access.
    """
    # URL-decode the key (S3 event records are URL-encoded)
    decoded_key = unquote_plus(key)

    # Block path traversal attempts
    if ".." in decoded_key or decoded_key.startswith("/"):
        raise ValueError(f"Invalid S3 key (path traversal attempt): {decoded_key}")

    # Ensure the object is under the expected prefix
    if not decoded_key.startswith("uploads/"):
        raise ValueError(
            f"S3 key is outside the allowed 'uploads/' prefix: {decoded_key}"
        )

    return decoded_key


def _validate_image_metadata(bucket: str, key: str) -> dict:
    """
    Fetch object metadata and validate content type and size before
    downloading the full object.
    """
    head = s3_client.head_object(Bucket=bucket, Key=key)

    content_type = head.get("ContentType", "")
    content_length = head.get("ContentLength", 0)

    if content_type not in ALLOWED_CONTENT_TYPES:
        raise ValueError(
            f"Unsupported content type '{content_type}' for s3://{bucket}/{key}. "
            f"Allowed: {ALLOWED_CONTENT_TYPES}"
        )

    if content_length > MAX_IMAGE_SIZE_BYTES:
        raise ValueError(
            f"Image too large ({content_length} bytes) for s3://{bucket}/{key}. "
            f"Max allowed: {MAX_IMAGE_SIZE_BYTES} bytes."
        )

    if content_length == 0:
        raise ValueError(f"Image is empty (0 bytes): s3://{bucket}/{key}")

    return head


def _read_image_from_s3(bucket: str, key: str) -> bytes:
    """Download the image bytes from S3."""
    response = s3_client.get_object(Bucket=bucket, Key=key)
    return response["Body"].read()


def _process_image(image_data: bytes, source_key: str) -> dict:
    """
    Core image processing logic. Replace this stub with real processing
    (thumbnailing, labelling, etc.).

    Returns a dict with processing results/metadata.
    """
    result = {
        "source_key": source_key,
        "size_bytes": len(image_data),
        "processed_at": datetime.utcnow().isoformat() + "Z",
        "status": "processed",
        # Add real processing outputs here (e.g., labels, thumbnail key, etc.)
    }

    logger.info(
        "Image processed",
        extra={"source_key": source_key, "size_bytes": len(image_data)},
    )
    return result


def _write_results_to_s3(result: dict, source_key: str) -> str:
    """
    Write the JSON processing result to the results bucket.
    Returns the destination S3 key.
    """
    # Derive a deterministic but unique result key
    base_name = os.path.splitext(os.path.basename(source_key))[0]
    result_key = f"results/{base_name}-{uuid.uuid4().hex[:8]}.json"

    s3_client.put_object(
        Bucket=RESULTS_BUCKET,
        Key=result_key,
        Body=json.dumps(result, default=str),
        ContentType="application/json",
        # Server-side encryption — always encrypt data at rest
        ServerSideEncryption="aws:kms",
    )

    logger.info(
        "Results written to S3",
        extra={"results_bucket": RESULTS_BUCKET, "result_key": result_key},
    )
    return result_key


def _send_notification(source_key: str, result_key: str, status: str, detail: str = ""):
    """Publish a processing notification to SNS."""
    message = {
        "source_key": source_key,
        "result_key": result_key,
        "status": status,
        "detail": detail,
        "timestamp": datetime.utcnow().isoformat() + "Z",
    }

    sns_client.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=f"Image Processing {status.capitalize()}: {os.path.basename(source_key)}",
        Message=json.dumps(message, default=str),
    )

    logger.info("SNS notification sent", extra={"status": status, "source_key": source_key})


def _process_single_record(record: dict):
    """Handle one S3 event record end-to-end."""
    bucket = record["s3"]["bucket"]["name"]
    raw_key = record["s3"]["object"]["key"]

    # Validate and sanitise the key
    key = _validate_s3_key(raw_key)

    logger.info("Processing image", extra={"bucket": bucket, "key": key})

    try:
        # Validate metadata (content type, size) before downloading
        _validate_image_metadata(bucket, key)

        # Download
        image_data = _read_image_from_s3(bucket, key)

        # Process
        result = _process_image(image_data, key)

        # Write results
        result_key = _write_results_to_s3(result, key)

        # Notify success
        _send_notification(source_key=key, result_key=result_key, status="success")

    except ValueError as ve:
        # Validation errors (bad content type, size, path traversal)
        logger.warning("Validation failed for %s: %s", key, ve)
        _send_notification(
            source_key=key,
            result_key="",
            status="validation_error",
            detail=str(ve),
        )
        # Do NOT re-raise — the message is malformed and retrying won't help.

    except ClientError as ce:
        error_code = ce.response["Error"]["Code"]
        logger.error(
            "AWS API error processing %s: %s — %s",
            key,
            error_code,
            ce,
            exc_info=True,
        )
        # Re-raise so Lambda retries (transient AWS errors)
        raise

    except Exception:
        logger.exception("Unexpected error processing %s", key)
        raise


def lambda_handler(event, context):
    """
    Entry point for the Lambda function.

    Expected trigger: S3 PutObject event on the uploads bucket.
    """
    _validate_environment()

    records = event.get("Records", [])
    if not records:
        logger.warning("Received event with no records: %s", json.dumps(event))
        return {"statusCode": 200, "body": "No records to process."}

    errors = []
    for record in records:
        try:
            _process_single_record(record)
        except Exception as exc:
            errors.append(str(exc))

    if errors:
        # Raise so Lambda marks the invocation as failed and retries
        # (for SQS/async invocations with DLQ configured).
        raise RuntimeError(
            f"{len(errors)} record(s) failed processing: {'; '.join(errors)}"
        )

    return {
        "statusCode": 200,
        "body": json.dumps({"processed": len(records)}),
    }